import { Component, OnInit } from '@angular/core';
import { Posmanagement } from './interfaces/posmanagement.model';
import { SelectionModel } from '@angular/cdk/collections';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { stagger40ms } from '../../../../ux/animations/stagger.animation';
import { FormArray, FormControl, FormGroup, UntypedFormControl } from '@angular/forms';
import { UntilDestroy } from '@ngneat/until-destroy';
import { PosmanagementService } from './posmanagement.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';
import { SharedService } from 'src/app/shared/shared.service';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { ActivitymasterService } from '../../setup/activitymaster/activitymaster.service';
import { UnitmasterService } from '../../setup/unitmaster/unitmaster.service';

@UntilDestroy()
@Component({
  selector: 'ux-posmanagement',
  templateUrl: './posmanagement.component.html',
  styleUrls: ['./posmanagement.component.scss'],
  animations: [
    fadeInUp400ms,
    stagger40ms
  ],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class PosmanagementComponent implements OnInit {
  layoutCtrl = new UntypedFormControl('fullwidth');
  posmanagement: Posmanagement[];
  selection = new SelectionModel<Posmanagement>(true, []);
  searchCtrl = new UntypedFormControl();

  posmanagement_list = [];
  page_mode = 'Grid'; //Grid or AddEdit

  //pages
  posnames: any;
  posForm: FormGroup;
  pos_list = [];

  constructor(
    private posmanagementService: PosmanagementService,
    private authService: AuthService,
    private sharedService: SharedService,
    private dialog: MatDialog,
    private _snackBar: MatSnackBar,
    private activityService: ActivitymasterService,
    private unitService: UnitmasterService
  ) {
  }

  unitSubscription: Subscription;
  activitySubscription: Subscription;
  activitymaster_list = [];
  unitmaster_list = [];
  ngOnInit() {
    this.unitService.getAllUnits();
    this.unitSubscription = this.unitService.unitsChanged
      .subscribe(
        (units: any[]) => {
          this.unitmaster_list = units;
          console.log(this.unitmaster_list);
        }
      );

    this.activityService.getAllActivties();
    this.activitySubscription = this.activityService.activitiesChanged
      .subscribe(
        (activities: any[]) => {
          this.activitymaster_list = activities;
          this.activitymaster_list.forEach(element => {
            element.selected = false;
            element.billing_items = [];
          });
        }
      );
  }

  unitselected_index: number;
  onSelectUnit(unit: any, index: number) {
    this.unitselected_index = undefined;
    this.activityselected_index = undefined;
    setTimeout(() => {
      this.unitselected_index = index;

      //get the activities for the selected unit
      this.getActivitiesByUnit(unit._id);
    }, 200);

  }

  private getActivitiesByUnit(unit_id: string) {
    this.posmanagementService.getActivitiesByUnit(unit_id)
      .then((res: any) => {
        console.log(res);
        if (res.messagecode === 100) {
          if (res.posdata.activities.length > 0) {
            let selected_activities = res.posdata.activities;
            this.activitymaster_list.forEach(element => {
              let objIdx = selected_activities.findIndex(x => x._id === element._id && x.selected === true);
              if (objIdx != -1) {
                element.selected = true;
                element.billing_items = selected_activities[objIdx].billing_items;
              } else {
                element.selected = false;
                element.billing_items = [];
              }
            });
          } else {
            //uncheck all selected activites and reset
            this.activitymaster_list.forEach(element => {
              element.selected = false;
              element.billing_items = [];
            });
          }
        }
      })
      .catch((err: any) => {

      });
  }

  activityselected_index: number;
  onSetupClicked(activity: any, index: number) {
    console.log(activity);
    this.activityselected_index = undefined;
    setTimeout(() => {
      this.activityselected_index = index;
      //pages
      if (activity.billing_items.length > 0) {
        this.posnames = new FormArray([]);

        for (let entity of activity.billing_items) {
          this.posnames.push(
            new FormGroup({
              'itemid': new FormControl(entity.itemid),
              'itemname': new FormControl(entity.itemname),
              'itemprice': new FormControl(entity.itemprice),
              'itemdescription': new FormControl(entity.itemdescription)
            })
          )
        }
        //we have to check if the count is more than 2, else we will push one empty entity
        if (this.posnames.length < 2) {
          this.posnames.push(
            new FormGroup({
              'itemid': new FormControl(''),
              'itemname': new FormControl(''),
              'itemprice': new FormControl(''),
              'itemdescription': new FormControl('')
            })
          )
        }

        this.posForm = new FormGroup({
          'posnames': this.posnames
        });
      } else {
        this.posnames = new FormArray([]);
        for (let index = 0; index < 2; index++) {
          this.posnames.push(
            new FormGroup({
              'itemid': new FormControl(''),
              'itemname': new FormControl(''),
              'itemprice': new FormControl(''),
              'itemdescription': new FormControl('')
            })
          )
        };
        this.posForm = new FormGroup({
          'posnames': this.posnames
        });
      }

    }, 200);

  }

  get poscontrols() {
    return (<FormArray>this.posForm.get('posnames')).controls;
  }

  onAddNew() {
    (<FormArray>this.posForm.get('posnames')).push(
      new FormGroup({
        'itemid': new FormControl(''),
        'itemname': new FormControl(''),
        'itemprice': new FormControl(''),
        'itemdescription': new FormControl('')
      })
    );
  }

  onDeleteItem(index: number) {
    let objIdx = this.poscontrols.findIndex(x => x.value.itemid === this.posnames.value[index].itemid);
    this.poscontrols.splice(objIdx, 1);
    this.posnames.value.splice(index, 1);
  }

  onSavePos() {
    console.log(this.posnames);
    let billing_list = [];
    this.posnames.value.forEach(element => {
      if ((element.itemname != '' && element.itemname != null) && (element.itemprice != '' && element.itemprice != null)) {
        element.itemid = Guid.newGuid();
        billing_list.push(element);
      }
    });
    this.activitymaster_list[this.activityselected_index].billing_items = billing_list;
    console.log(this.activitymaster_list);

    let billData = {
      unit_id: this.unitmaster_list[this.unitselected_index]._id,
      activities: this.activitymaster_list
    }
    console.log(billData);

    this.posmanagementService.savePOS(billData)
      .then(res => {
        let resData: any = res;
        console.log(resData);
        if (resData.messagecode === 101) {
          //clear all data
          this.activityselected_index = undefined;
          this.unitselected_index = undefined;

        }

      })
      .catch(err => {
        console.log(err);
      })
  }

  openSnackBar(title: string, message: string) {
    this._snackBar.open(message, title, {
      duration: 3000,
      horizontalPosition: 'center',
      verticalPosition: 'bottom',
    });
  }
}

class Guid {
  static newGuid() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
      var r = Math.random() * 16 | 0,
        v = c == 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  }
}